SELECT `time`, id_device, error, s.start_date_time, s.end_date_time, d.id, IFNULL(u.nvmActivePower, 0.001) AS nvmActivePower FROM ${datatablename} u LEFT JOIN device d ON d.id = u.id_device LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone
WHERE
u.id_device = #{id} AND DATE_FORMAT(CONVERT_TZ( u.time, '+00:00', t.`offset` ), "%Y-%m-%d %H:%i:%s") <= DATE_FORMAT( #{current_time}, "%Y-%m-%d 18:00:00") ORDER BY u.`time` DESC LIMIT 1;

SELECT COUNT(*) AS totalRecord FROM ( SELECT u.id FROM alert u LEFT JOIN error e ON e.id = u.id_error WHERE u.id_device = #{id_device} AND u.id_error = #{id_error} AND u.status = 1 AND u.is_delete = 0 AND e.is_delete = 0 AND e.status = 1
UNION ALL
SELECT u.id FROM alert_queue u LEFT JOIN error e ON e.id = u.id_error WHERE u.id_device = #{id_device} AND u.id_error = #{id_error} AND u.status = 1 AND u.is_delete = 0 AND e.is_delete = 0 AND e.status = 1 AND u.is_queue = 0 ) t;

    	SELECT
    	COUNT(e.id) as totalRecord
		FROM `error` as e
		WHERE e.id = #{id_error} 
		AND e.is_delete = 0 
		AND e.`status` = 1;

