UPDATE site s, (
SELECT #{item.id} AS id, #{item.ActualGeneration} AS ActualGeneration, #{item.EstimatedGeneration} AS EstimatedGeneration
) t SET s.PerformanceRatioYesterday = IF(t.ActualGeneration IS NULL OR t.EstimatedGeneration IS NULL OR t.EstimatedGeneration <= 0, NULL, ROUND(t.ActualGeneration / t.EstimatedGeneration * 100 , 1)) WHERE s.id = t.id

