SELECT DATE_FORMAT(MIN(time), "%Y-%m-%d %H:%i:%s") AS start_time, DATE_FORMAT(MAX(time), "%Y-%m-%d %H:%i:%s") AS end_time, TIMESTAMPDIFF(MINUTE, MIN(time), MAX(time)) AS error_duration FROM ( SELECT time, error, SUM(is_new_group) OVER (ORDER BY time) AS grp FROM ( SELECT u.error, u.time, CASE WHEN LAG(u.error) OVER (ORDER BY u.time) = u.error THEN 0 ELSE 1 END AS is_new_group FROM ${datatablename} u LEFT JOIN device d ON u.id_device = d.id WHERE u.id_device = #{id_device} AND u.time BETWEEN DATE_ADD(#{time}, INTERVAL -120 MINUTE) AND #{time} ) x ) y WHERE
error = #{error}
error != 139
GROUP BY grp ORDER BY start_time DESC LIMIT 1;

