mapper.select:
SELECT
CASE WHEN MIN(CASE WHEN ${field} > 0 AND ${field} != 0.001 THEN 1 ELSE 0 END ) = 1 AND TIMESTAMPDIFF(MINUTE, MIN(time), MAX(time)) >= 120 THEN 1 ELSE 0 END AS ${field}, DATE_FORMAT( ( SELECT time FROM ${data_table_name} WHERE time > ( SELECT time FROM ${data_table_name} dv WHERE dv.${field} = 0 ANd dv.${field} is not null ORDER BY time DESC LIMIT 1 ) AND ${field} is not null ORDER BY time ASC LIMIT 1 ), '%Y-%m-%d %H:%i:%s') AS ${field}_time,
FROM ${data_table_name} WHERE id_device = #{id_device} AND time BETWEEN DATE_ADD(#{time}, INTERVAL -120 MINUTE) AND #{time}
